+    final void recomputePopupLayout() {
+        popupNeedsReconfiguring = true;
+        if (popup == null || !popup.isShowing()) {
+            return;
+        }
+        Node popupContent = getPopupContent();
+        popupContent.applyCss();
+        sizePopup(false);
+        if (popupContent instanceof Parent p) {
+            p.layout();
+        }
+        reconfigurePopup();
